					try {
						int cp = Integer.parseInt(raw.substring(i + 2, i + 10), 16);
						resolved.appendCodePoint(cp);
						i += 10;
						continue;
					} catch (NumberFormatException e) {
						// not a valid Unicode escape, treat \ as literal character
					}
